          "type": "string"
        },
        "name_of_person_or_agency_carrying_out_project": {
          "description": "Name of the person or agency responsible for carrying out the project .If you cannot fill this, write \"N/A\". If this field should not be filled by you (for example, it belongs to another person or office), leave it blank (empty string \"\").",
          "title": "Name Of Person Or Agency Carrying Out Project",
          "type": "string"
        }
      },
      "required": [
        "name_of_public_agency_approving_project",
        "name_of_person_or_agency_carrying_out_project"
