      "description": "Type of exemption claimed for the project",
      "properties": {
        "ministerial_sec_21080_b1_15268": {
          "default": "",
          "description": "Check if the project is exempt as a ministerial project under Sec. 21080(b)(1); 15268",
          "enum": [
            "true",
            "false",
            "N/A",
            ""
          ],
          "title": "Ministerial Sec 21080 B1 15268",
          "type": "string"
        },
        "declared_emergency_sec_21080_b3_15269_a": {
          "default": "",
          "description": "Check if the project is exempt as a declared emergency under Sec. 21080(b)(3); 15269(a)",
          "enum": [
            "true",
            "false",
            "N/A",
            ""
          ],
          "title": "Declared Emergency Sec 21080 B3 15269 A",
          "type": "string"
        },
        "emergency_project_sec_21080_b4_15269_b_c": {
