          "title": "Statutory Exemptions State Code Number",
          "type": "string"
        }
      },
      "title": "ExemptStatus",
      "type": "object"
    },
    "ExemptionJustification": {
      "description": "Explanation of why the project is exempt",
      "properties": {
        "reasons_why_project_is_exempt": {
          "description": "Explanation supporting the exemption determination .If you cannot fill this, write \"N/A\". If this field should not be filled by you (for example, it belongs to another person or office), leave it blank (empty string \"\").",
